mapper.select:
SELECT document_id, user_id, document_name, source_path, status, created_at, updated_at
FROM t_document
WHERE user_id = #{userId}
  AND document_name = #{documentName}
LIMIT 1

mapper.update:
UPDATE t_document
SET status = #{status}
WHERE document_id = #{documentId}

UPDATE t_document
SET source_path = #{sourcePath},
    status = #{status}
WHERE document_id = #{documentId}
